const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');

console.log('');
console.log('=== Mon Deen - Patch + Deploy ===');
console.log('');

// Trouver le dossier projet
const appDir = __dirname;
console.log('[OK] Dossier : ' + appDir);

// Supprimer src/src si mal cree
const srcSrc = path.join(appDir, 'src', 'src');
if (fs.existsSync(srcSrc)) {
  fs.rmSync(srcSrc, { recursive: true, force: true });
  console.log('[OK] src/src supprime');
}

// Fichiers a ecrire (base64)
const files = {
  "src/App.jsx": "",
  "src/pages/Ramadan.jsx": "",
  "src/pages/Quran.jsx": "",
  "src/pages/Statistics.jsx": "",
  "src/pages/CerclePrivee.jsx": "",
  "src/pages/Zakat.jsx": "",
  "src/pages/Dashboard.jsx": ""
};

// Ecrire chaque fichier
for (const [rel, b64] of Object.entries(files)) {
  const dest = path.join(appDir, rel.replace(/\//g, path.sep));
  const dir = path.dirname(dest);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(dest, Buffer.from(b64, 'base64'));
  console.log('[OK] ' + rel);
}

console.log('');

// Build
console.log('Build en cours...');
try {
  execSync('npm run build', { cwd: appDir, stdio: 'inherit' });
  console.log('[OK] Build reussi');
} catch(e) {
  console.log('[XX] Build echoue'); process.exit(1);
}

// Git
console.log('');
console.log('Git commit + push...');
try {
  execSync('git add .', { cwd: appDir, stdio: 'pipe' });
  const date = new Date().toISOString().slice(0,10);
  try {
    execSync('git commit -m "Nouvelles pages ' + date + '"', { cwd: appDir, stdio: 'pipe' });
    console.log('[OK] Commit effectue');
  } catch(e) {
    console.log('[--] Rien a committer');
  }
  execSync('git push origin main', { cwd: appDir, stdio: 'pipe' });
  console.log('[OK] Push GitHub OK');
} catch(e) {
  console.log('[!!] Erreur Git : ' + e.message);
}

// Vercel
console.log('');
console.log('Deploiement Vercel...');
try {
  execSync('vercel --prod --yes', { cwd: appDir, stdio: 'inherit' });
  console.log('');
  console.log('================================');
  console.log('DEPLOIEMENT TERMINE !');
  console.log('https://mon-deen-gules.vercel.app');
  console.log('================================');
} catch(e) {
  console.log('[!!] Erreur Vercel - essaie: vercel login');
}
